WebLink.url:
{!REQUIRESCRIPT("/soap/ajax/38.0/connection.js")} 
{!REQUIRESCRIPT("/soap/ajax/38.0/apex.js")} 

var records = {!GETRECORDIDS($ObjectType.Sansan_CI__BizCard__c)}; 

if (records.length != 1 ) { 
    alert('1つ選択してください。');
} else { 
	var ret = sforce.apex.execute('Sansan_CI.BizCard_WebService','linkToLead',{bId:records[0],lId:"{!Lead.Id}"}); 
	if(ret != ''){
	    location.href = ret;
	}else{
		alert('{!$Label.sansan_ci__MESSAGE_ERROR_UNAVAILABLECONTACTADMIN}');
	}
}
